// True positive: a single production function whose body spans well beyond the
// default 50-line threshold, with no branching or nesting so only the
// long-function rule fires. Detection is AST-based (real function span).
pub fn accumulate_totals() -> i64 {
    let mut total = 0i64;
    let step_00 = 0i64;
    let step_01 = 1i64;
    let step_02 = 2i64;
    let step_03 = 3i64;
    let step_04 = 4i64;
    let step_05 = 5i64;
    let step_06 = 6i64;
    let step_07 = 7i64;
    let step_08 = 8i64;
    let step_09 = 9i64;
    let step_10 = 10i64;
    let step_11 = 11i64;
    let step_12 = 12i64;
    let step_13 = 13i64;
    let step_14 = 14i64;
    let step_15 = 15i64;
    let step_16 = 16i64;
    let step_17 = 17i64;
    let step_18 = 18i64;
    let step_19 = 19i64;
    let step_20 = 20i64;
    let step_21 = 21i64;
    let step_22 = 22i64;
    let step_23 = 23i64;
    let step_24 = 24i64;
    let step_25 = 25i64;
    let step_26 = 26i64;
    let step_27 = 27i64;
    let step_28 = 28i64;
    let step_29 = 29i64;
    let step_30 = 30i64;
    let step_31 = 31i64;
    let step_32 = 32i64;
    let step_33 = 33i64;
    let step_34 = 34i64;
    let step_35 = 35i64;
    let step_36 = 36i64;
    let step_37 = 37i64;
    let step_38 = 38i64;
    let step_39 = 39i64;
    let step_40 = 40i64;
    total += step_00 + step_01 + step_02 + step_03 + step_04;
    total += step_05 + step_06 + step_07 + step_08 + step_09;
    total += step_10 + step_11 + step_12 + step_13 + step_14;
    total += step_15 + step_16 + step_17 + step_18 + step_19;
    total += step_20 + step_21 + step_22 + step_23 + step_24;
    total += step_25 + step_26 + step_27 + step_28 + step_29;
    total += step_30 + step_31 + step_32 + step_33 + step_34;
    total += step_35 + step_36 + step_37 + step_38 + step_39;
    total += step_40;
    total
}
